import { useEffect, useMemo, useState, useCallback } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Tabs,
  TabsContent,
  TabsList,
  TabsTrigger,
} from "@/components/ui/tabs";
import { Badge } from "@/components/ui/badge";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";

import { apiClient, authService } from "@/App";
import { toast } from "sonner";

import {
  Plus,
  BookOpen,
  Users,
  ClipboardList,
  Award,
  TrendingUp,
  Download,
  Eye,
  Search,
  Phone,
  Mail,
} from "lucide-react";

import jsPDF from "jspdf";

// =========================
// SAFE ROLE NORMALIZER
// =========================
const normalizeRole = (role) => {
  if (!role) return "";

  const r = String(role).toLowerCase();

  const map = {
    admin: "school_admin",
    schooladmin: "school_admin",
    school_admin: "school_admin",
    superadmin: "super_admin",
    super_admin: "super_admin",
    teacher: "teacher",
    finance: "finance",
    secretary: "secretary",
    student: "student",
  };

  return map[r] || r;
};

// =========================
// GRADE HELPERS
// =========================
const calculateCBEGrade = (marks) => {
  if (marks >= 80) return "EE";
  if (marks >= 60) return "ME";
  if (marks >= 40) return "AE";
  return "BE";
};

const gradeColor = (grade) => {
  switch (grade) {
    case "EE":
      return "bg-green-100 text-green-800";
    case "ME":
      return "bg-blue-100 text-blue-800";
    case "AE":
      return "bg-yellow-100 text-yellow-800";
    default:
      return "bg-red-100 text-red-800";
  }
};

const approvalColor = (status) => {
  switch (status) {
    case "approved":
      return "bg-green-100 text-green-800";
    case "rejected":
      return "bg-red-100 text-red-800";
    default:
      return "bg-yellow-100 text-yellow-800";
  }
};

const attendanceColor = (status) => {
  switch (status) {
    case "present":
      return "bg-green-100 text-green-800";
    case "absent":
      return "bg-red-100 text-red-800";
    case "late":
      return "bg-yellow-100 text-yellow-800";
    default:
      return "bg-blue-100 text-blue-800";
  }
};

// =========================
// COMPONENT
// =========================
const TeacherPortal = () => {
  const rawUser = authService.getUser();

  const user = useMemo(() => {
    if (!rawUser) return null;
    return { ...rawUser, role: normalizeRole(rawUser.role) };
  }, [rawUser]);

  const [students, setStudents] = useState([]);
  const [exams, setExams] = useState([]);
  const [attendance, setAttendance] = useState([]);

  const [loading, setLoading] = useState(true);

  const [selectedClass, setSelectedClass] = useState("all");
  const [searchTerm, setSearchTerm] = useState("");

  const [resultsDialogOpen, setResultsDialogOpen] = useState(false);
  const [attendanceDialogOpen, setAttendanceDialogOpen] = useState(false);
  const [progressDialogOpen, setProgressDialogOpen] = useState(false);

  const [selectedStudent, setSelectedStudent] = useState(null);
  const [studentResults, setStudentResults] = useState([]);

  const [resultForm, setResultForm] = useState({
    exam_id: "",
    student_id: "",
    subject: "",
    marks: "",
    grade: "",
    teacher_comments: "",
  });

  const [attendanceForm, setAttendanceForm] = useState({
    student_id: "",
    date: new Date().toISOString().split("T")[0],
    status: "present",
    remarks: "",
  });

  // =========================
  // DATA FETCH (SAFE)
  // =========================
  const fetchTeacherData = useCallback(async () => {
    try {
      setLoading(true);

      const [studentsRes, examsRes, attendanceRes] = await Promise.all([
        apiClient.get("/students?approval_status=all").catch(() => ({ data: [] })),
        apiClient.get("/exams").catch(() => ({ data: [] })),
        apiClient.get("/attendance?approval_status=all").catch(() => ({ data: [] })),
      ]);

      setStudents(studentsRes.data || []);
      setExams(examsRes.data || []);
      setAttendance(attendanceRes.data || []);
    } catch (err) {
      toast.error("Failed to load teacher data");
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchTeacherData();
  }, [fetchTeacherData]);

  // =========================
  // DERIVED DATA
  // =========================
  const myClasses = useMemo(() => {
    return [...new Set(
      (students || [])
        .map((s) => s.class_name || s.year_of_study)
        .filter(Boolean)
    )];
  }, [students]);

  const filteredStudents = useMemo(() => {
    return (students || []).filter((student) => {
      const classValue = student.class_name || student.year_of_study || "";

      const matchesClass =
        selectedClass === "all" || classValue === selectedClass;

      const matchesSearch =
        student.full_name?.toLowerCase().includes(searchTerm.toLowerCase()) ||
        student.admission_number?.toLowerCase().includes(searchTerm.toLowerCase());

      return matchesClass && matchesSearch;
    });
  }, [students, selectedClass, searchTerm]);

  const todayAttendance = useMemo(() => {
    const today = new Date().toISOString().split("T")[0];
    return (attendance || []).filter((a) => a.date === today).length;
  }, [attendance]);

  // =========================
  // SUBMIT RESULT
  // =========================
  const handleSubmitResult = async (e) => {
    e.preventDefault();

    try {
      const payload = {
        ...resultForm,
        marks: Number(resultForm.marks),
        max_marks: 100,
      };

      const res = await apiClient.post("/results", payload);

      toast.success(
        res?.data?.approval_status === "pending"
          ? "Submitted for approval"
          : "Result saved"
      );

      setResultsDialogOpen(false);
      setResultForm({
        exam_id: "",
        student_id: "",
        subject: "",
        marks: "",
        grade: "",
        teacher_comments: "",
      });

      fetchTeacherData();
    } catch (err) {
      toast.error(err?.response?.data?.detail || "Failed to submit result");
    }
  };

  // =========================
  // ATTENDANCE
  // =========================
  const handleMarkAttendance = async (e) => {
    e.preventDefault();

    try {
      await apiClient.post("/attendance", {
        entity_type: "student",
        entity_id: attendanceForm.student_id,
        date: attendanceForm.date,
        status: attendanceForm.status,
        remarks: attendanceForm.remarks,
      });

      toast.success("Attendance recorded");
      setAttendanceDialogOpen(false);

      fetchTeacherData();
    } catch (err) {
      toast.error(err?.response?.data?.detail || "Failed attendance");
    }
  };

  // =========================
  // STUDENT PROGRESS
  // =========================
  const viewStudentProgress = async (student) => {
    setSelectedStudent(student);

    try {
      const res = await apiClient.get(`/results/${student.id}`);
      setStudentResults(res.data || []);
    } catch {
      setStudentResults([]);
    }

    setProgressDialogOpen(true);
  };

  // =========================
  // LOADING
  // =========================
  if (loading) {
    return (
      <div className="flex items-center justify-center h-[70vh]">
        Loading...
      </div>
    );
  }

  // =========================
  // UI
  // =========================
  return (
    <div className="space-y-6">

      <div>
        <h2 className="text-3xl font-bold text-white">
          Teacher Portal
        </h2>

        <p className="text-slate-400">
          Welcome back {user?.full_name || "Teacher"}
        </p>
      </div>

      {/* KEEP YOUR FULL UI BELOW UNCHANGED (already correct structurally) */}
      {/* Only logic fixes were applied above */}

    </div>
  );
};

export default TeacherPortal;
